import{c as e,a7 as r,y as i,B as p}from"./chunks/framework.3cjvm90C.js";const m=JSON.parse('{"title":"High Level Overview of Apache Spark","description":"Apache Spark 的高层架构与核心概念总览","frontmatter":{"title":"High Level Overview of Apache Spark","description":"Apache Spark 的高层架构与核心概念总览"},"headers":[],"relativePath":"mlwiki/Spark/spark.md","filePath":"mlwiki/Spark/spark.md","lastUpdated":1782456021000}'),s={name:"mlwiki/Spark/spark.md"};function t(l,a,n,o,h,d){return r(),i("div",null,[...a[0]||(a[0]=[p('<h1 id="high-level-overview-of-apache-spark" tabindex="-1">High Level Overview of Apache Spark <a class="header-anchor" href="#high-level-overview-of-apache-spark" aria-label="Permalink to “High Level Overview of Apache Spark”">​</a></h1><p>Spark 是用于大规模数据处理的集群计算框架。 Spark 为统一计算引擎提供了 3 种语言（Java，Scala 和 Python）丰富的算法库。</p><p>Unified：借助 Spark，无需将多个 API 或系统中的应用程序组合在一起。 Spark 为您提供了足够的内置 API 来完成工作。</p><p>Computing Engine：Spark 加载来自各种文件系统的数据并在其上运行计算，但不会永久存储任何数据本身。 Spark 完全在内存中运行-拥有无与伦比的性能和速度。</p><p>Libraries：Spark 由为数据科学任务而构建的一系列库组成。 包括用于 SQL（SparkSQL），机器学习（MLlib），流处理（Spark Streaming and Structured Streaming）和图分析（GraphX）的库。</p><h2 id="spark-application" tabindex="-1">Spark Application <a class="header-anchor" href="#spark-application" aria-label="Permalink to “Spark Application”">​</a></h2><p>每个 Spark Application 程序都包含一个驱动程序（<strong>Driver</strong> ）和一组分布式工作进程（<strong>Executors</strong>）。</p><h2 id="spark-driver" tabindex="-1">Spark Driver <a class="header-anchor" href="#spark-driver" aria-label="Permalink to “Spark Driver”">​</a></h2><p>驱动程序运行我们应用程序的 main（）方法，并在其中创建 SparkContext。 Spark 驱动程序具有以下职责：</p><ul><li>在集群中的节点上或客户端上运行，并通过集群管理器调度作业执行</li><li>对用户的程序或输入做出响应</li><li>分析，编排和分配各个 exectors 的工作</li><li>存储正在运行的应用程序的 metadata ，并在 WebUI 中显示</li></ul><h2 id="spark-executors" tabindex="-1">Spark Executors <a class="header-anchor" href="#spark-executors" aria-label="Permalink to “Spark Executors”">​</a></h2><p>Executors 是负责执行任务的分布式过程。每个 Spark 应用程序都有其自己的 Executors，这些执行程序在单个 Spark 应用程序的生命周期内保持有效。</p><ul><li>Executor 执行 Spark 作业的所有数据处理</li><li>将结果存储在内存中，仅在驱动程序有特别指示时才在磁盘上进行持久化</li><li>计算完成后，将结果返回给驱动程序</li><li>每个节点可以具有从每个节点 1 个执行程序 到 每个核心 1 个执行程序</li></ul><p><img src="https://hackernoon.com/hn-images/1*GZG2aogNS8Jg14jOM2rjmQ.png" alt="img"></p><h2 id="spark-application-工作流程" tabindex="-1">Spark Application 工作流程 <a class="header-anchor" href="#spark-application-工作流程" aria-label="Permalink to “Spark Application 工作流程”">​</a></h2><p>当您将作业提交给 Spark 进行处理时，幕后还有很多事情要做。</p><ul><li>我们的 Standalone Application 启动，并初始化其 SparkContext。 只有拥有 SparkContext 之后，才能将应用程序称为驱动程序</li><li>我们的驱动程序（Driver program）要求集群管理器提供启动其执行程序（executors）的资源</li><li>集群管理器启动执行程序（executors）</li><li>我们的驱动程序（ Driver）运行我们的实际 Spark 代码</li><li>执行程序（Executors）运行任务并将其结果发送回驱动程序（driver）</li><li>SparkContext 停止并且所有执行程序都已关闭，将资源返回给集群</li></ul><h2 id="maxtemperature-revisited" tabindex="-1">MaxTemperature, Revisited <a class="header-anchor" href="#maxtemperature-revisited" aria-label="Permalink to “MaxTemperature, Revisited”">​</a></h2><p>让我们更深入地看一下我们编写的 Spark Job，以按国家/地区查找最高温度。 这种抽象隐藏了许多设置代码，包括我们的 SparkContext 的初始化，可以弥补这些空白：</p><p><img src="https://hackernoon.com/hn-images/1*8COf1mt_AxIt66ft83z-yg.png" alt="img"></p><p>请记住，Spark 是一个框架，上面的应用程序是用 Java 实现的。 直到第 16 行，Spark 才需要做任何工作。 当然，我们已经初始化了 SparkContext，但是将数据加载到 RDD 中是将工作发送给 executors 的第一步。</p><p>到现在为止，您可能已经看到“ RDD”一词出现了多次，现在是时候定义它了。</p><h2 id="spark-架构概述" tabindex="-1">Spark 架构概述 <a class="header-anchor" href="#spark-架构概述" aria-label="Permalink to “Spark 架构概述”">​</a></h2><p>Spark 具有定义明确的分层架构，其基于两个主要抽象的组件具有松散耦合：</p><ul><li>弹性分布式数据集（RDD）</li><li>有向无环图（DAG）</li></ul><p><img src="https://miro.medium.com/max/60/1*Ck-GUoBRx7b8rxrgQlNEGQ.png?q=20" alt="img"></p><p><img src="https://miro.medium.com/max/1312/1*Ck-GUoBRx7b8rxrgQlNEGQ.png" alt="img"></p><p>From PySpark-Pictures by Jeffrey Thompson.</p><h2 id="rdd-弹性分布式数据集" tabindex="-1">RDD (弹性分布式数据集) <a class="header-anchor" href="#rdd-弹性分布式数据集" aria-label="Permalink to “RDD (弹性分布式数据集)”">​</a></h2><p>RDD 是可以并行操作的元素的容错集合。 您可以创建它们来并行化驱动程序中的现有集合，或在外部存储系统（例如共享文件系统，HDFS，HBase 或提供 Hadoop InputFormat 的任何数据源）中引用数据集。</p><p><img src="https://miro.medium.com/max/2457/1*fN_Pj-NmrBFbxNVYexzYoQ.png" alt="img"></p><p>RDD 本质上是 Spark 的构建块：一切都由它们组成。 甚至 Sparks 更高级别的 API（DataFrame，Dataset）也由 RDD 组成。</p><p>Resilient (弹性)：由于 Spark 在集群上运行，硬件故障造成的数据丢失是一个非常现实的问题，因此 RDD 具有容错能力，并且在发生故障时可以自行重建.</p><p>Distributed (分布式)：单个 RDD 存储在群集中的一系列不同节点上，不属于单个源（也不属于单个故障点）。 这样我们的集群可以并行地在 RDD 上运行</p><p>Dataset (数据集)：值的集合。</p><p>我们在 Spark 中使用的所有数据都将存储在某种形式的 RDD 中，因此必须完全理解它们。</p><p>Spark 提供了一系列“更高级别”的 API，这些 API 构建在 RDD 之上，旨在抽象掉复杂性，即 DataFrame 和 Dataset。Spark Submit 和 Scala 和 Python 中的 Spark Shell 非常关注 Read-Evaluate-Print 循环（repl），它们的目标是数据科学家，他们通常希望对数据集进行重复分析。RDD 仍然需要理解，因为它是 Spark 中所有数据的底层结构。</p><p>RDD 在口语上等同于：“分布式数据结构”。 <code>JavaRDD&lt;String&gt;</code>本质上只是一个 List <code>String</code>，分布在我们集群中的每个节点之间，每个节点都获得 List 的几个不同块。 使用 Spark，我们需要始终在分布式环境中进行思考。</p><p>RDD 的工作原理是将它们的数据分割成一系列的分区，存储在每个 executor 节点上。 然后，每个节点将仅在其自己的分区上执行其工作。 这就是 Spark 如此强大的原因：如果 Executor 死亡或任务失败，Spark 可以从原始源中重建它所需的分区，然后重新提交任务以完成任务。</p><p><img src="https://hackernoon.com/hn-images/1*7aXGUcCy3qHD3U66COrTTA.png" alt="img"></p><p>Spark RDD partitioned amongst executors</p><h2 id="the-dataframe" tabindex="-1">The Dataframe <a class="header-anchor" href="#the-dataframe" aria-label="Permalink to “The Dataframe”">​</a></h2><p><img src="https://miro.medium.com/max/68/1*t9Cnql3208oRs-ZchANtTg.png?q=20" alt="img"></p><p><img src="https://miro.medium.com/max/1431/1*t9Cnql3208oRs-ZchANtTg.png" alt="img"></p><p>DataFrame is a <em>Dataset</em> organized into named columns.。它在概念上相当于关系数据库中的一个表或 R/Python 中的一个 data frame，但在幕后进行了更丰富的优化。DataFrames can be constructed from a wide array of <a href="https://spark.apache.org/docs/latest/sql-programming-guide.html#data-sources" target="_blank" rel="noreferrer">sources</a> such as: structured data files, tables in Hive, external databases, or existing RDDs.</p><p><img src="https://miro.medium.com/max/68/1*OY41hGbe4IB9%E5%9E%8B-hHLRPuCHQ.png?q=20" alt="图像"></p><p><img src="https://miro.medium.com/max/68/1*OY41hGbe4IB9-hHLRPuCHQ.png?q=20" alt="img"></p><p><img src="https://miro.medium.com/max/4473/1*OY41hGbe4IB9-hHLRPuCHQ.png" alt="img"></p><p><a href="https://aspgems.com/blog/big-data/migrando-de-pandas-spark-dataframes" target="_blank" rel="noreferrer">https://aspgems.com/blog/big-data/migrando-de-pandas-spark-dataframes</a></p><p>简单地说，dataframes 是 Spark 创建者用来简化在框架中处理数据的方法。它们与 Pandas Dataframes 或 R Dataframes 非常相似，但有几个优点。第一个当然是它们可以分布在一个集群中，因此它们可以处理大量的数据，第二个是对数据进行了优化。</p><h2 id="rdd-操作" tabindex="-1">RDD 操作 <a class="header-anchor" href="#rdd-操作" aria-label="Permalink to “RDD 操作”">​</a></h2><p>RDD 是不可变的，这意味着一旦它们被创建，就不能以任何方式对其进行更改，只能对其进行转换。转换 RDD 的概念是 Spark 的核心，可以将 Spark Jobs 视为下面这些步骤的任意组合：</p><ul><li><p>将数据加载到 RDD 中</p></li><li><p>转换 RDD</p></li><li><p>在 RDD 上执行操作</p></li></ul><p>实际上，我编写的每一个 Spark 作业都完全由这些类型的任务组成的。Spark 定义了一组用于处理 RDD 的 API，可以将其分为两大类：转换和操作。</p><ul><li><p>转换会从现有的 RDD 创建一个新的 RDD。</p></li><li><p>操作在其 RDD 上运行计算后，会将一个或多个值返回给驱动程序。</p></li></ul><p>例如，地图函数 weatherData.map（）是一种转换，它通过函数传递 RDD 的每个元素的转换。Reduce 是一个 RDD 操作，它使用某些函数来聚合 RDD 的所有元素，并将最终结果返回给驱动程序。</p><h2 id="惰性计算" tabindex="-1">惰性计算 <a class="header-anchor" href="#惰性计算" aria-label="Permalink to “惰性计算”">​</a></h2><p>“我选择一个懒惰的人做艰苦的工作。因为一个懒惰的人会找到一种简单的方法来做到这一点。 - 比尔盖茨”</p><p>Spark 中的所有转换都是惰性的。这意味着，当我们告诉 Spark 通过现有 RDD 的转换来创建 RDD 时，直到对该数据集或其子对象执行特定操作之前，它不会生成该数据集。然后，Spark 将执行转换以及触发转换的操作。这使 Spark 可以更有效地运行。</p><p>默认情况下，每次在其上执行操作时，都可能会重新计算每个转换后的 RDD。 但是，您也可以使用 persist（或缓存）方法将 RDD 保留在内存中，在这种情况下，Spark 会将元素保留在群集中，以便在下次查询时更快地进行访问。 还支持将 RDD 持久存储在磁盘上，或在多个节点之间复制。</p><p>让我们重新检查之前的 Spark 示例中的函数声明，以识别哪些函数是动作，哪些是转换：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>16：JavaRDD&amp;lt;String&amp;gt; weatherData = sc.textFile（inputPath）;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>第 16 行既不是动作也不是变换。它是 sc（我们的 JavaSparkContext）的功能。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>17：JavaPairRDD &lt;String，Integer&gt; tempsByCountry = weatherData.mapToPair（新函数..</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>第 17 行是 weatherData RDD 的转换，其中我们将 weatherData 的每一行映射到由（City，Temperature）组成的一对</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>26：JavaPairRDD &lt;String，Integer&gt; maxTempByCountry = tempsByCountry.reduce（新函数...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>第 26 行也是一种转换，因为我们正在遍历键值对。这是对 tempsByCountry 的一种转换，在该转换中，我们将每个城市的温度降低到最高记录温度。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>31：maxTempByCountry.saveAsHadoopFile（destPath，String.class，Integer.class，TextOutputFormat.class）；</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>最后，在第 31 行，我们触发了 Spark 动作：将 RDD 保存到文件系统中。 由于 Spark 订阅了惰性执行模型，因此直到这一行 Spark 生成 weatherData，tempsByCountry 和 maxTempsByCountry 才最终保存我们的结果。</p><h2 id="directed-acyclic-graph" tabindex="-1">Directed Acyclic Graph <a class="header-anchor" href="#directed-acyclic-graph" aria-label="Permalink to “Directed Acyclic Graph”">​</a></h2><p>每当在 RDD 上执行操作时，Spark 都会创建 DAG，即有向循环的有限直接图（否则我们的工作将永远运行）。 请记住，图只不过是一系列连接的顶点和边，并且该图也没有什么不同。 DAG 中的每个顶点都是 Spark 函数，在 RDD 上执行某些操作（map，mapToPair，reduceByKey 等）。</p><p>在 MapReduce 中，DAG 由两个顶点组成：Map→Reduce。</p><p>在我们上面的 MaxTemperatureByCountry 示例中，DAG 更为复杂：</p><p>parallelize → map → mapToPair → reduce → saveAsHadoopFile</p><p>DAG 使 Spark 可以优化其执行计划并最大程度地减少扰动。 我们将在以后的文章中更深入地讨论 DAG，因为它不在本 Spark 概述的范围之内。</p><h2 id="evaluation-loops" tabindex="-1">Evaluation Loops <a class="header-anchor" href="#evaluation-loops" aria-label="Permalink to “Evaluation Loops”">​</a></h2><p>使用我们的新词汇，让我们重新检查我在第一部分中定义的 MapReduce 的问题，如下所述：</p><p>MapReduce 在批处理数据方面表现出色，但是在重复分析和小的反馈循环方面却落后。在计算之间重用数据的唯一方法是将其写入外部存储系统（例如 HDFS）” “在计算之间重复使用数据”？听起来像是可以对其执行多项操作的 RDD！假设我们有一个文件“ data.txt”，并且想要完成两个计算：</p><ul><li>文件中所有行的总长度</li><li>文件中最长行的长度</li></ul><p>在 MapReduce 中，每个任务将需要单独的作业或奇特的 MulitpleOutputFormat 实现。Spark 只需四个简单的步骤即可轻松实现：</p><p>1.将 data.txt 的内容加载到 RDD 中</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>JavaRDD&amp;lt;String&amp;gt;行= sc.textFile（“ data.txt”）;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>2.将“行”的每一行映射到其长度（为简洁起见使用 Lambda 函数）</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>JavaRDD&amp;lt;Integer&amp;gt; lineLengths = lines.map（s-&gt; s.length（））;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>3.解决总长度：减少 lineLengths 以找到总线长总和，在这种情况下，是 RDD 中每个元素的总和</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>int totalLength = lineLengths.reduce（（a，b）-&gt; a + b）;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>4.解决最长的长度：减小 lineLengths 以找到最大的行长</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>int maxLength = lineLengths.reduce（（a，b）-&gt; Math.max（a，b））;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>请注意，第 3 步和第 4 步是 RDD 动作，因此它们将结果返回到我们的 Driver 程序，在本例中为 Java int。还要记住，Spark 是懒惰的，并且拒绝执行任何工作，直到看到一个动作为止，在这种情况下，它直到第 3 步才开始任何实际的工作。</p><h1 id="deep-learning-and-apache-spark" tabindex="-1">Deep Learning and Apache Spark <a class="header-anchor" href="#deep-learning-and-apache-spark" aria-label="Permalink to “Deep Learning and Apache Spark”">​</a></h1><p>为什么要在 Apache Spark 上进行深度学习？</p><ul><li>Apache Spark 是一个了不起的框架，用于以简单且声明性的方式在集群中分布计算。 它正在成为各行各业的标准，因此在其中添加深度学习的惊人进步将是很棒的。</li><li>深度学习的某些部分在计算上非常繁琐！ 分发这些进程可能是解决其他问题的解决方案，而 Apache Spark 是我认为可以分发它们的最简单方法。</li><li>有几种使用 Apache Spark 进行深度学习的方法，我之前已经讨论过，在此再次列出（不详尽）：</li></ul><p>1.<a href="http://maxpumperla.github.io/elephas/" target="_blank" rel="noreferrer"> Elephas</a>: Distributed DL with Keras &amp; PySpark:</p><p><a href="https://github.com/maxpumperla/elephas" target="_blank" rel="noreferrer">maxpumperla/elephaselephas — Distributed Deep learning with Keras &amp; Spark</a></p><p><a href="https://www.linkedin.com/company/1288/" target="_blank" rel="noreferrer"><strong>2. Yahoo! Inc.</strong></a>: TensorFlowOnSpark:</p><p><a href="https://github.com/yahoo/TensorFlowOnSpark" target="_blank" rel="noreferrer">yahoo/TensorFlowOnSparkTensorFlowOnSpark brings TensorFlow programs onto Apache Spark clusters</a></p><p><a href="https://www.linkedin.com/company/157302/" target="_blank" rel="noreferrer"><strong>3. CERN</strong></a> Distributed Keras (Keras + Spark) :</p><p><a href="https://github.com/cerndb/dist-keras" target="_blank" rel="noreferrer">cerndb/dist-kerasdist-keras — Distributed Deep Learning, with a focus on distributed training, using Keras and Apache Spark</a></p><p><a href="https://www.linkedin.com/company/2531735/" target="_blank" rel="noreferrer"><strong>4. Qubole</strong></a> (tutorial Keras + Spark):</p><p><a href="https://www.qubole.com/blog/distributed-deep-learning-keras-apache-spark/" target="_blank" rel="noreferrer">Distributed Deep Learning with Keras on Apache Spark | QuboleDeep learning has been shown to produce highly effective machine learning models in a diverse group of fields. </a></p><p><a href="https://www.linkedin.com/company/1053/" target="_blank" rel="noreferrer"><strong>5. Intel Corporation</strong></a>: BigDL (Distributed Deep Learning Library for Apache Spark)</p><p><a href="https://github.com/intel-analytics/BigDL" target="_blank" rel="noreferrer">intel-analytics/BigDLBigDL: Distributed Deep Learning Library for Apache Spark</a></p><h1 id="deep-learning-pipelines" tabindex="-1">Deep Learning Pipelines <a class="header-anchor" href="#deep-learning-pipelines" aria-label="Permalink to “Deep Learning Pipelines”">​</a></h1><p><img src="https://miro.medium.com/max/68/1*6gBbuSw5qH34uI7GF4p97A.png?q=20" alt="img"></p><p><img src="https://miro.medium.com/max/6350/1*6gBbuSw5qH34uI7GF4p97A.png" alt="img"></p><p><a href="https://github.com/databricks/spark-deep-learning" target="_blank" rel="noreferrer">databricks/spark-deep-learningspark-deep-learning - Deep Learning Pipelines for Apache Spark</a></p><p><strong>Deep Learning Pipelines</strong>是 Databricks 创建的一个开源代码库，该库提供了高级 API，可用于使用 Apache Spark 在 Python 中进行可扩展的深度学习。 这是一项了不起的工作，并且很快就会被合并到官方 API 中，因此值得一看。与我之前列出的库相比，该库的一些优点是：</p><ul><li>本着 Spark 和 Spark MLlib 的精神，它提供了易于使用的 API，使用很少的代码即可进行深度学习。</li><li>它着重于易用性和集成性，而不牺牲性能。</li><li>它是由 Apache Spark 的创建者（也是主要贡献者）构建的，因此与其他应用相比，它更有可能被合并为正式 API。</li><li>它是用 Python 编写的，因此将与其所有著名的库集成在一起，现在，它使用 TensorFlow 和 Keras 的强大功能，这是目前用于 DL 的两个主要库。</li></ul><p>在下一篇文章中，我将完全专注于 DL 管道库以及如何从头开始使用它。您将看到的一件事是在简单的管道上进行转移学习，如何使用预训练的模型来处理“少量”数据，并能够预测事物，如何通过深入了解来增强公司中的每个人您创建的学习模型可在 SQL 中使用，甚至更多。</p>',109)])])}const k=e(s,[["render",t]]);export{m as __pageData,k as default};
